import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { Table, TableBody, TableCell, TableHead, TableRow, Button, TextField, Box, Select, MenuItem } from '@material-ui/core';

export default function PurchaseManagement() {
  const [purchases, setPurchases] = useState([]);
  const [items, setItems] = useState([]);
  const [companies, setCompanies] = useState([]);
  const [newPurchase, setNewPurchase] = useState({ item: { id: '' }, quantity: 0, cost: 0, company: { id: '' } });

  useEffect(() => {
    axios.get('http://localhost:8080/api/purchases').then(res => setPurchases(res.data));
    axios.get('http://localhost:8080/api/items').then(res => setItems(res.data));
    axios.get('http://localhost:8080/api/companies').then(res => setCompanies(res.data));
  }, []);

  const addPurchase = () => {
    axios.post('http://localhost:8080/api/purchases', newPurchase).then(res => {
      setPurchases([...purchases, res.data]);
      setNewPurchase({ item: { id: '' }, quantity: 0, cost: 0, company: { id: '' } });
    });
  };

  return (
    <div>
      <Box marginBottom={2}>
        <Select
          value={newPurchase.item.id}
          onChange={e => setNewPurchase({ ...newPurchase, item: { id: e.target.value } })}
        >
          {items.map(item => (
            <MenuItem key={item.id} value={item.id}>{item.name}</MenuItem>
          ))}
        </Select>
        <TextField
          label="Quantity"
          type="number"
          value={newPurchase.quantity}
          onChange={e => setNewPurchase({ ...newPurchase, quantity: parseInt(e.target.value) })}
        />
        <TextField
          label="Cost"
          type="number"
          value={newPurchase.cost}
          onChange={e => setNewPurchase({ ...newPurchase, cost: parseFloat(e.target.value) })}
        />
        <Select
          value={newPurchase.company.id}
          onChange={e => setNewPurchase({ ...newPurchase, company: { id: e.target.value } })}
        >
          {companies.map(company => (
            <MenuItem key={company.id} value={company.id}>{company.name}</MenuItem>
          ))}
        </Select>
        <Button onClick={addPurchase} color="primary" variant="contained">Add Purchase</Button>
      </Box>
      <Table>
        <TableHead>
          <TableRow>
            <TableCell>Item</TableCell>
            <TableCell>Quantity</TableCell>
            <TableCell>Cost</TableCell>
            <TableCell>Company</TableCell>
          </TableRow>
        </TableHead>
        <TableBody>
          {purchases.map(purchase => (
            <TableRow key={purchase.id}>
              <TableCell>{purchase.item.name}</TableCell>
              <TableCell>{purchase.quantity}</TableCell>
              <TableCell>{purchase.cost}</TableCell>
              <TableCell>{purchase.company.name}</TableCell>
            </TableRow>
          ))}
        </TableBody>
      </Table>
    </div>
  );
}
